{
var seed = GetInt(parameters, "seed", context.Seed);
var spiralType = GetChoice(parameters, "spiralType", "archimedean");
var arms = GetFloat(parameters, "arms", 1);
var turns = GetFloat(parameters, "turns", 3);
var lineWidth = GetFloat(parameters, "lineWidth", 0.08f);
var distortion = GetFloat(parameters, "distortion", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);
var mask = new PixelBuffer(size, size);

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size * 2f - 1f;
    var v = (y + 0.5f) / size * 2f - 1f;

    var r = MathF.Sqrt(u * u + v * v);
    var theta = MathF.Atan2(v, u);

    // Noise distortion
    if (distortion > 0f)
    {
        var d = TileableFractalNoise(u * 2f + 5f, v * 2f + 5f, 8, 2, 0.5f, 2f, seed) * distortion * 0.5f;
        r += d * 0.3f;
    }

    var spiralVal = 0f;
    switch (spiralType)
    {
        case "logarithmic":
            // log spiral: r = a * e^(b*theta)
            theta += arms * MathF.Log(r + 0.001f) * turns;
            break;
        default: // archimedean
            // Archimedean: r = a + b*theta
            theta = (r * turns * MathF.PI * 2f - theta * arms) * arms;
            break;
    }

    var dTheta = MathF.Abs(MathF.IEEERemainder(theta, MathF.PI * 2f / arms));
    var dist = MathF.Min(dTheta, MathF.PI * 2f / arms - dTheta) / (MathF.PI * 2f / arms);
    spiralVal = 1f - SmoothStep(0f, lineWidth, dist);

    // Fade at edges
    var fade = 1f - SmoothStep(0.7f, 1f, r);
    spiralVal *= fade;

    if (invert) spiralVal = 1f - spiralVal;

    buffer.SetPixel(x, y, spiralVal, spiralVal, spiralVal, 1f);
    mask.SetPixel(x, y, spiralVal, spiralVal, spiralVal, 1f);
});

return buffer;
}
